import { workflow, node, trigger, newCredential, expr } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'Set Sample Data',
    parameters: {
      assignments: {
        assignments: [
          {
            id: 'field-1',
            name: 'message',
            value: 'Hello from Set node!',
            type: 'string'
          },
          {
            id: 'field-2',
            name: 'status',
            value: 'success',
            type: 'string'
          },
          {
            id: 'field-3',
            name: 'count',
            value: 42,
            type: 'number'
          }
        ]
      }
    }
  }
});

export default workflow('manual-set-preview', 'Manual Trigger + Set Node Preview')
  .add(manualTrigger)
  .to(setNode);
